const TARGET_CHARS = 2800;
const OVERLAP_CHARS = 400;
const MIN_LETTERS_PER_CHUNK = 40;
const BATCH_SIZE = 32;

function stripFrontmatter(md) {
  if (!md.startsWith("---")) return md;
  const end = md.indexOf("\n---", 3);
  if (end === -1) return md;
  return md.slice(end + 4).replace(/^\s+/, "");
}

function paragraphSplit(text, target) {
  if (text.length <= target) return text.length;
  const window = text.slice(0, target);
  const paragraphCut = window.lastIndexOf("\n\n");
  if (paragraphCut > target * 0.6) return paragraphCut + 2;
  const sentenceCut = window.lastIndexOf(". ");
  if (sentenceCut > target * 0.6) return sentenceCut + 2;
  return target;
}

function subdivideLongSection(text) {
  if (text.length <= TARGET_CHARS) return [text];
  const out = [];
  let i = 0;
  while (i < text.length) {
    const end = i + paragraphSplit(text.slice(i), TARGET_CHARS);
    out.push(text.slice(i, end).trim());
    if (end >= text.length) break;
    i = Math.max(end - OVERLAP_CHARS, i + 1);
  }
  return out;
}

function letterCount(s) {
  return (s.match(/[A-Za-z]/g) || []).length;
}

function chunkMarkdown(doc) {
  const body = stripFrontmatter(doc.content);
  const sections = body.split(/\n(?=## )/).map(function (s) { return s.trim(); }).filter(Boolean);
  const pieces = [];
  for (const section of sections) {
    for (const piece of subdivideLongSection(section)) pieces.push(piece);
  }
  const out = [];
  let chunkIdx = 0;
  for (const piece of pieces) {
    if (letterCount(piece) < MIN_LETTERS_PER_CHUNK) continue;
    out.push({ source: doc.source, chunk_idx: chunkIdx, content: piece });
    chunkIdx++;
  }
  return out;
}

const inputItem = items[0].json;
const sources = inputItem.sources || [];
const allChunks = [];
for (const doc of sources) {
  for (const chunk of chunkMarkdown(doc)) allChunks.push(chunk);
}

const runStart = new Date().toISOString();
const totalBatches = Math.max(1, Math.ceil(allChunks.length / BATCH_SIZE));
const batches = [];
for (let i = 0; i < allChunks.length; i += BATCH_SIZE) {
  const batch = allChunks.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      batch: batch,
      inputs: batch.map(function (c) { return c.content; }),
      run_start: runStart,
      batch_idx: batches.length,
      total_batches: totalBatches,
      total_chunks: allChunks.length,
    },
  });
}

return batches;

const embedResponse = items[0].json;
const vectors = embedResponse.vectors || [];

const loopItem = $("Loop Batches").item.json;
const batch = loopItem.batch;
const runStart = loopItem.run_start;
const batchIdx = loopItem.batch_idx;

if (!Array.isArray(batch) || !Array.isArray(vectors) || batch.length !== vectors.length) {
  throw new Error("Vector count " + vectors.length + " does not match chunk count " + (batch ? batch.length : 0) + " for batch " + batchIdx);
}

function sqlString(s) {
  return "'" + String(s).replace(/'/g, "''") + "'";
}

function vectorLiteral(v) {
  return sqlString("[" + v.map(function (x) { return Number(x).toFixed(6); }).join(",") + "]");
}

const valuesRows = batch.map(function (c, i) {
  return "(" + sqlString(c.source) + ", " + Number(c.chunk_idx) + ", " + sqlString(c.content) + ", " + vectorLiteral(vectors[i]) + "::vector, NOW())";
}).join(",\n  ");

const sql = "INSERT INTO public.rag_chunks (source, chunk_idx, content, embedding, updated_at)\nVALUES\n  " + valuesRows + "\nON CONFLICT (source, chunk_idx) DO UPDATE\nSET content = EXCLUDED.content,\n    embedding = EXCLUDED.embedding,\n    updated_at = NOW();";

return [{ json: { sql: sql, batch_size: batch.length, run_start: runStart, batch_idx: batchIdx } }];
